}

module.exports = async function(data) {
    const payload = data.$trigger.payload;
	let summary = null;

    if(Object.keys(payload.blocks).includes("create")){
        summary = generateSummary(payload.blocks.create);
    }

    if(null == summary && Object.keys(payload.blocks).includes("update")){
        summary = generateSummary(payload.blocks.update);
    }

    const keys = data.$trigger.keys ?? [data.$trigger.key];
	return {summary, keys};
}

function generateSummary(blocks){
