module.exports = async function(data) {
    const item = data.seo_item_data;
    const payload = data.$trigger.payload;

	let seo = {};
    let key = item.id;
    if(item.seo){
        seo.id = item.seo;
    }
    seo.title = item.title;
    seo.image = item.cover;
    seo.owner = item.id;

    if(null != item.summary){
        seo.description = item.summary;
    }

    if(payload.blocks.update){
        let update = generateSummary(payload.blocks.update);
        if(null !== update){
            seo.description = update;
        }
    }

    if(payload.blocks.create){
        let create = generateSummary(payload.blocks.create);
        if(null !== create){
            seo.description = create;
        }
    }

	return {seo, key};
}

module.exports = async function(data) {
	let keys = data.$trigger.keys ?? [data.$trigger.key];
    let slug = data.$trigger.payload.title
		.toLowerCase()
		.trim()
		.replace(/[^\w\s-]/g, '')
		.replace(/[\s_-]+/g, '-')
		.replace(/^-+|-+$/g, '');
    return {keys, slug}
}
